import{_ as e,c as a,o as t,a as i}from"./app.fc4dff93.js";const u=JSON.parse('{"title":"\u6211\u4EEC\u8BE5\u600E\u6837\u9762\u5BF9\u4EBA\u751F\u56F0\u5883","description":"","frontmatter":{},"headers":[{"level":2,"title":"\u9965\u8352\u4E4B\u6240\u4EE5\u4E3A\u9965\u8352\uFF0C\u56F0\u5883\u4E4B\u6240\u4EE5\u4E3A\u56F0\u5883","slug":"\u9965\u8352\u4E4B\u6240\u4EE5\u4E3A\u9965\u8352\uFF0C\u56F0\u5883\u4E4B\u6240\u4EE5\u4E3A\u56F0\u5883","link":"#\u9965\u8352\u4E4B\u6240\u4EE5\u4E3A\u9965\u8352\uFF0C\u56F0\u5883\u4E4B\u6240\u4EE5\u4E3A\u56F0\u5883","children":[]},{"level":2,"title":"\u8BC0\u7A8D","slug":"\u8BC0\u7A8D","link":"#\u8BC0\u7A8D","children":[]},{"level":2,"title":"\u4F53\u4F1A","slug":"\u4F53\u4F1A","link":"#\u4F53\u4F1A","children":[]}],"relativePath":"do-not-starve/how-should-we-face-the-difficulties-of-life.md","lastUpdated":1672671275000}'),d={name:"do-not-starve/how-should-we-face-the-difficulties-of-life.md"},r=i('<h1 id="\u6211\u4EEC\u8BE5\u600E\u6837\u9762\u5BF9\u4EBA\u751F\u56F0\u5883" tabindex="-1">\u6211\u4EEC\u8BE5\u600E\u6837\u9762\u5BF9\u4EBA\u751F\u56F0\u5883 <a class="header-anchor" href="#\u6211\u4EEC\u8BE5\u600E\u6837\u9762\u5BF9\u4EBA\u751F\u56F0\u5883" aria-hidden="true">#</a></h1><p>\u8FD1\u6765\uFF0C\u6211\u8FF7\u4E0A\u4E86\u4E00\u6B3E\u6E38\u620F\u2014\u2014\u300A\u9965\u8352\u300B\u3002\u6211\u8FD9\u4E2A\u4EBA\u5185\u5FC3\u6BD4\u8F83\u522B\u626D\uFF0C\u5982\u679C\u5355\u7EAF\u4E3A\u4E86\u723D\u6253\u6E38\u620F\uFF0C\u6211\u4F1A\u6709\u8D1F\u7F6A\u611F\u3002\u4E3A\u4E86\u80FD\u5B89\u5FC3\u6253\u6E38\u620F\uFF0C\u6211\u5F97\u627E\u4E2A\u51A0\u5195\u5802\u7687\u7684\u7406\u7531\u3002\u601D\u7D22\u4E86\u534A\u5929\uFF0C\u6211\u627E\u5230\u7684\u7406\u7531\u662F\uFF1A\u6211\u5728\u601D\u7D22\u4EBA\u4E16\u95F4\u6C38\u6052\u7684\u4E00\u4E2A\u96BE\u9898\u2014\u2014\u300C\u6211\u4EEC\u8BE5\u600E\u6837\u9762\u5BF9\u4EBA\u751F\u56F0\u5883\u300D\u3002</p><p>\u8FD9\u5E76\u4E0D\u5168\u662F\u80E1\u626F\uFF0C\u300A\u9965\u8352\u300B\u7684\u5267\u60C5\uFF0C\u8BB2\u7684\u5C31\u662F\u4E00\u4E2A\u79D1\u5B66\u5BB6\u5728\u5371\u9669\u4E16\u754C\u91CC\u8270\u96BE\u6C42\u751F\u3002\u867D\u7136\u5C11\u6570\u5927\u4F6C\u53EF\u4EE5\u5F88\u8F7B\u677E\u5730\u5C06\u300C\u9965\u8352\u300D\u8FC7\u6210\u300C\u9971\u8352\u300D\u3001\u300C\u95F2\u5F97\u614C\u300D\uFF0C\u4F46\u662F\u5927\u591A\u6570\u73A9\u5BB6\u90FD\u4F1A\u611F\u89C9\u8FD9\u6E38\u620F\u5F88\u56F0\u96BE\u3002\u8FD9\u50CF\u6781\u4E86\u73B0\u5B9E\u751F\u6D3B\uFF0C\u5C11\u6570\u5929\u9009\u4E4B\u5B50\u80FD\u591F\u653E\u8086\u5730\u5403\u3001\u653E\u8086\u5730\u7231\uFF0C\u6D3B\u5F97\u7279\u522B\u7CBE\u5F69\uFF0C\u7EDD\u5927\u591A\u6570\u4EBA\u8FC7\u5F97\u5C31\u8C28\u5C0F\u614E\u5FAE\u3001\u5355\u8C03\u4E4F\u5473\u3002\u5BF9\u4E8E\u540E\u8005\u6765\u8BF4\uFF0C\u751F\u6D3B\u5C31\u662F\u4E00\u4E2A\u56F0\u5883\u3002\u6211\u4E5F\u662F\u540E\u8005\u7684\u4E00\u4EFD\u5B50\uFF0C\u73A9\u4E2A\u6E38\u620F\u90FD\u5F97\u627E\u4E2A\u7406\u7531\uFF0C\u6CA1\u90A3\u4E48\u5229\u843D\u3002</p><p>\u300C\u751F\u6D3B\u662F\u56F0\u5883\u300D\uFF0C\u6E38\u620F\u91CC\u5B58\u5728\uFF0C\u6E38\u620F\u5916\u4E5F\u5B58\u5728\uFF0C\u8FC7\u53BB\u5B58\u5728\uFF0C\u73B0\u5728\u4E5F\u5B58\u5728\uFF0C\u4E0D\u5206\u6C11\u65CF\u3001\u4E0D\u5206\u6587\u5316\u5730\u5B58\u5728\u3002\u6BD4\u5982\u8001\u820D\u7684\u300A\u9A86\u9A7C\u7965\u5B50\u300B\uFF0C\u8F66\u592B\u7965\u5B50\u60F3\u8981\u4E70\u4E00\u8F86\u81EA\u5DF1\u7684\u9EC4\u5305\u8F66\uFF0C\u7ED3\u679C\u4E70\u4E86\u4E09\u6B21\u53C8\u5356\u4E86\u4E09\u6B21\u3002\u53C8\u6BD4\u5982\u6D77\u660E\u5A01\u7684\u300A\u8001\u4EBA\u4E0E\u6D77\u300B\uFF0C\u6E14\u592B\u8001\u4EBA\u60F3\u9493\u5F97\u4E00\u6761\u5927\u9C7C\uFF0C\u7ED3\u679C\u9493\u5230\u4E4B\u540E\uFF0C\u5927\u9C7C\u88AB\u9CA8\u9C7C\u5543\u5F97\u53EA\u5269\u9C7C\u9AA8\u5934\u3002\u4ED6\u4EEC\u90FD\u5F92\u52B3\u65E0\u529F\u3001\u767D\u8D39\u529B\u6C14\uFF0C\u8EAB\u5904\u56F0\u5883\u4E4B\u4E2D\u65E0\u529B\u6446\u8131\u3002</p><p>\u8C08\u5230\u8FD9\u91CC\uFF0C\u6211\u4EEC\u5DF2\u7ECF\u73A9\u300A\u9965\u8352\u300B\u548C\u601D\u7D22\u4EBA\u751F\u96BE\u9898\u6302\u94A9\u3002\u5F53\u7136\u5199\u8FD9\u7BC7\u6587\u7AE0\uFF0C\u6211\u4EEC\u4E0D\u80FD\u5355\u7EAF\u5730\u57CB\u6028\u300C\u751F\u6D3B\u662F\u56F0\u5883\u300D\uFF0C\u800C\u662F\u8981\u901A\u8FC7\u600E\u4E48\u73A9\u300A\u9965\u8352\u300B\uFF0C\u6765\u5C1D\u8BD5\u89E3\u7B54\u300C\u751F\u6D3B\u662F\u56F0\u5883\u300D\u8FD9\u4E2A\u95EE\u9898\u3002</p><h2 id="\u9965\u8352\u4E4B\u6240\u4EE5\u4E3A\u9965\u8352\uFF0C\u56F0\u5883\u4E4B\u6240\u4EE5\u4E3A\u56F0\u5883" tabindex="-1">\u9965\u8352\u4E4B\u6240\u4EE5\u4E3A\u9965\u8352\uFF0C\u56F0\u5883\u4E4B\u6240\u4EE5\u4E3A\u56F0\u5883 <a class="header-anchor" href="#\u9965\u8352\u4E4B\u6240\u4EE5\u4E3A\u9965\u8352\uFF0C\u56F0\u5883\u4E4B\u6240\u4EE5\u4E3A\u56F0\u5883" aria-hidden="true">#</a></h2><p>\u641E\u5F97\u8FD9\u4E48\u60E8\uFF0C\u6211\u80AF\u5B9A\u662F\u8981\u67E5\u653B\u7565\uFF0C\u770B\u770B\u8FD9\u4E2A\u6E38\u620F\u600E\u4E48\u73A9\uFF0C\u7ED3\u679C\u5462\uFF1F\u653B\u7565\u6211\u67E5\u4E86\u4E0D\u5C11\uFF0C\u90FD\u5F88\u6709\u9053\u7406\uFF0C\u6BD4\u5982\u8BA9\u6211\u8FFD\u7740\u725B\u7FA4\uFF0C\u725B\u7CAA\u53EF\u4EE5\u751F\u6D3B\u3001\u65BD\u80A5\uFF0C\u6709\u91CE\u72D7\u8FC7\u6765\u65F6\u5F80\u725B\u54E5\u8EAB\u8FB9\u4E00\u8EB2\uFF0C\u725B\u54E5\u5C31\u4F1A\u6559\u91CE\u72D7\u505A\u72D7\u7684\u9053\u7406\u3002\u4E5F\u6709\u7684\u4EBA\u8981\u6211\u8FFD\u7740\u732A\u54E5\uFF0C\u732A\u54E5\u5FC3\u5584\uFF0C\u5582\u51E0\u5757\u8089\u5C31\u53EF\u4EE5\u88AB\u6536\u4E70\uFF0C\u7136\u540E\u5E2E\u5FD9\u780D\u6811\u3001\u6253\u602A\u7B49\u7B49\u3002</p><p>\u8FD9\u4E9B\u6280\u5DE7\u90FD\u5F88\u6709\u9053\u7406\uFF0C\u4F46\u6B63\u662F\u56E0\u4E3A\u6280\u5DE7\u592A\u591A\u4E86\uFF0C\u53CD\u800C\u8BA9\u6211\u4E0D\u77E5\u9053\u8BE5\u600E\u4E48\u505A\uFF0C\u800C\u4E14\u7167\u7740\u653B\u7565\u73A9\u6E38\u620F\uFF0C\u4E5F\u6CA1\u6709\u4EC0\u4E48\u610F\u601D\u3002</p><p>\u540E\u6765\u6211\u53D1\u73B0\u4E00\u4E2A\u8BC0\u7A8D\uFF0C\u5229\u7528\u8FD9\u4E2A\u8BC0\u7A8D\uFF0C\u6211\u4E0D\u4EC5\u6D3B\u8FC7\u4E86\u51AC\u5929\uFF0C\u8FD8\u6D3B\u8FC7\u4E86\u6625\u5929\uFF0C\u76F4\u5230\u590F\u5929\u88AB\u70ED\u6B7B\u3002</p><h2 id="\u8BC0\u7A8D" tabindex="-1">\u8BC0\u7A8D <a class="header-anchor" href="#\u8BC0\u7A8D" aria-hidden="true">#</a></h2><p>\u4EC0\u4E48\u8BC0\u7A8D\u5462\uFF1F\u5176\u5B9E\u5F88\u7B80\u5355\u2014\u2014\u603B\u662F\u4FDD\u6301\u6700\u4F73\u72B6\u6001\u3002</p><p>\u6E38\u620F\u4EBA\u7269\u4F1A\u997F\u3001\u4F1A\u6389\u8840\uFF0C\u8FD8\u4F1A\u7CBE\u795E\u72B6\u6001\u4E0D\u597D\u3002</p><p>\u6700\u5F00\u59CB\u65F6\uFF0C\u6211\u5076\u5C14\u4F1A\u6512\u7740\u98DF\u7269\uFF0C\u60F3\u7740\u7B49\u9505\u9020\u597D\u4E86\u4E4B\u540E\u5403\u4E2A\u9971\uFF0C\u8981\u4E48\u5C31\u662F\u89C9\u5F97\uFF0C\u73B0\u5728\u5403\u98DF\u7269\u3001\u52A0\u8840\u592A\u6D6A\u8D39\u4E86\u3002</p><p>\u8FD9\u6837\u4F1A\u51FA\u73B0\u4E00\u4E9B\u95EE\u9898\uFF0C\u90A3\u5C31\u662F\u300C\u6C38\u8FDC\u4F1A\u6709\u7A81\u53D1\u60C5\u51B5\u300D\uFF0C\u6BD4\u5982\u4F60\u7A7F\u8D8A\u6C99\u6F20\uFF0C\u7A81\u7136\u5C31\u7A9C\u51FA\u6765\u4E00\u7FA4\u72D7\u8FC7\u6765\u54AC\u4F60\u3002</p><p>\u4E8E\u662F\u4F60\u62FC\u4E86\u547D\u7684\u5230\u5904\u8DD1\u3001\u6216\u8005\u52C7\u6562\u5730\u4E0E\u4E00\u7FA4\u72D7\u51B3\u6597\uFF0C\u7ED3\u679C\u4E0D\u77E5\u4E0D\u89C9\u95F4\uFF0C\u4F60\u5C31\u997F\u5F97\u6389\u8840\u4E86\uFF0C\u4E4B\u540E\u5C31\u6B7B\u6389\u4E86\u3002</p><h2 id="\u4F53\u4F1A" tabindex="-1">\u4F53\u4F1A <a class="header-anchor" href="#\u4F53\u4F1A" aria-hidden="true">#</a></h2><p>\u6211\u5DF2\u7ECF\u5F00\u59CB\u5DE5\u4F5C\u4E86\uFF0C\u73B0\u5728\u6211\u8FD8\u662F\u7ECF\u5E38\u73A9\u9965\u8352\uFF0C\u6211\u89C9\u5F97\u73B0\u5B9E\u4E16\u754C\u5176\u5B9E\u548C\u9965\u8352\u4E16\u754C\u5F88\u50CF\u3002\u5F88\u591A\u65F6\u5019\u6211\u4EEC\u90FD\u4F1A\u9047\u5230\u7A81\u53D1\u4E8B\u4EF6\uFF0C\u6BD4\u5982\u7A81\u7136\u5931\u53BB\u5DE5\u4F5C\uFF0C\u6216\u8005\u4EB2\u4EBA\u7A81\u7136\u91CD\u75C5\uFF0C\u53C8\u6216\u8005\u5C31\u50CF\u65B0\u51A0\u75AB\u60C5\uFF0C\u7A81\u7136\u751F\u6D3B\u5C31\u53D1\u751F\u4E86\u5929\u7FFB\u5730\u8986\u5730\u6539\u53D8\u3002\u8FD9\u65F6\u5019\u67E5\u653B\u7565\u6709\u7528\u5417\uFF1F\u81EA\u7136\u662F\u6709\u7528\u7684\uFF0C\u80FD\u591F\u89E3\u51B3\u4E00\u65F6\u7684\u95EE\u9898\u3002</p><p>\u4F46\u5F88\u591A\u65F6\u5019\uFF0C\u6211\u4EEC\u5176\u5B9E\u662F\u9700\u8981\u4FDD\u6301\u7740\u81EA\u5DF1\u7684\u6700\u4F73\u72B6\u6001\uFF0C\u8FD9\u6837\u624D\u80FD\u5728\u5371\u9669\u6765\u4E34\u65F6\uFF0C\u771F\u6B63\u6709\u5B9E\u529B\u548C\u7CBE\u529B\u53BB\u5904\u7406\u5B83\u3002</p>',18),h=[r];function p(s,l,n,o,c,_){return t(),a("div",null,h)}const m=e(d,[["render",p]]);export{u as __pageData,m as default};
